string big_mul(string a, string b) &#123;    int alen = a.length();    int blen = b.length();    int clen = alen + blen;    // 翻转AB    reverse(a.begin(),a.end());    reverse(b.begin(),b.end());    vector&lt;int&gt; c(clen,0);        for(int i=0;i&lt;alen;i++) &#123;        for(int j=0;j&lt;blen;j++) &#123;            c[i+j] += (a[i] - &#x27;0&#x27;) * (b[j] - &#x27;0&#x27;);        &#125;    &#125;    string res;    int carry = 0; // 表示低位给过来的进位    for(int i=0;i&lt;clen;i++) &#123;        carry += c[i];        res.push_back((carry % 10)+&#x27;0&#x27;);        carry /= 10;    &#125;    for(int i=res.length()-1;i&gt;=0;i--) &#123;        if(res[i] == &#x27;0&#x27;) &#123;            res.pop_back();        &#125;else&#123;            break;        &#125;    &#125;    reverse(res.begin(),res.end());    if(res.length() == 0) res = &#x27;0&#x27;;    return res;&#125;
