KMP算法// 构建next数组，这个next数组是表示从当前到开头的最长公共前后缀vector&lt;int&gt; buildNext(const string&amp; pattern) &#123;    int m = pattern.length();    vector&lt;int&gt; next(m, 0);    for (int i = 1, j = 0; i &lt; m; i++) &#123;        while (j &gt; 0 &amp;&amp; pattern[j] != pattern[i]) &#123;            j = next[j - 1]; // 要循环跳转到前一个的next值        &#125;        if (pattern[i] == pattern[j]) &#123;            j++; // j的值还代表了最长匹配前后缀长度        &#125;        next[i] = j;    &#125;    return next;&#125;// 构建nextval数组vector&lt;int&gt; buildNextVal(const string&amp; pattern) &#123;    int m = pattern.length();    vector&lt;int&gt; nextval(m, 0);    int i = 1, len = 0;    while (i &lt; m) &#123;        if (pattern[i] == pattern[len]) &#123;            len++;            nextval[i] = len;            i++;        &#125; else if (len &gt; 0) &#123;            len = nextval[len - 1];        &#125; else &#123;            nextval[i] = 0;            i++;        &#125;    &#125;    return nextval;&#125;// KMP搜索算法vector&lt;int&gt; kmp(const string&amp; text, const string&amp; pattern) &#123;    int n = text.length();    int m = pattern.length();    vector&lt;int&gt; next = buildNext(pattern);    vector&lt;int&gt; positions; // 存储匹配开始的位置    int j = 0; // 模式字符串的索引    for (int i = 0; i &lt; n; i++) &#123;        while (j &gt; 0 &amp;&amp; pattern[j] != text[i]) &#123;            j = next[j - 1];        &#125;        if (pattern[j] == text[i]) &#123;            j++;        &#125;        if (j == m) &#123;            positions.push_back(i - m + 1); // 匹配成功，记录位置            j = next[j - 1]; // 继续查找下一个匹配        &#125;    &#125;    return positions;&#125;
排序归并排序public class MergeSort &#123;        public static void mergeSort(int[] arr) &#123;        if (arr == null || arr.length &lt; 2) return;        int[] temp = new int[arr.length];        sort(arr, 0, arr.length - 1, temp);    &#125;        private static void sort(int[] arr, int left, int right, int[] temp) &#123;        if (left &gt;= right) return;                int mid = left + (right - left) / 2;        sort(arr, left, mid, temp);        sort(arr, mid + 1, right, temp);        merge(arr, left, mid, right, temp);    &#125;        private static void merge(int[] arr, int left, int mid, int right, int[] temp) &#123;        int i = left, j = mid + 1, k = 0;                // 合并两个有序数组        while (i &lt;= mid &amp;&amp; j &lt;= right) &#123;            if (arr[i] &lt;= arr[j]) &#123;                temp[k++] = arr[i++];            &#125; else &#123;                temp[k++] = arr[j++];            &#125;        &#125;                // 复制剩余元素        while (i &lt;= mid) temp[k++] = arr[i++];        while (j &lt;= right) temp[k++] = arr[j++];                // 将临时数组复制回原数组        for (i = left, k = 0; i &lt;= right; i++, k++) &#123;            arr[i] = temp[k];        &#125;    &#125;&#125;
快速排序public class QuickSort &#123;        public static void quickSort(int[] arr) &#123;        if (arr == null || arr.length &lt; 2) return;        sort(arr, 0, arr.length - 1);    &#125;        private static void sort(int[] arr, int left, int right) &#123;        if (left &gt;= right) return;                int pivot = arr[left];  // 选择第一个元素作为基准        int i = left, j = right;                while (i &lt; j) &#123;            // 从右往左找第一个小于基准的值            while (i &lt; j &amp;&amp; arr[j] &gt;= pivot) j--;            // 从左往右找第一个大于基准的值            while (i &lt; j &amp;&amp; arr[i] &lt;= pivot) i++;            swap(arr, i, j);        &#125;        swap(arr, i, left); // i表示最后pivot的位置                sort(arr, left, i - 1);        sort(arr, i + 1, right);    &#125;&#125;
