   // O(n)时间选择出排序后的第K个元素，如果倒过来请给第N-K+1个元素    int quickSelect(vector&lt;int&gt;&amp; nums,int left, int right, int k) &#123;        if(left == right) return nums[left];        int partitionIdx = randomPartition(nums, left, right);        int curth = partitionIdx - left + 1;        if(curth == k)&#123;            return nums[partitionIdx];        &#125;else if (curth &gt; k) &#123;            return quickSelect(nums, left, partitionIdx-1, k);        &#125;else&#123;            return quickSelect(nums, partitionIdx+1, right, k-curth);        &#125;    &#125;    // 将最左边一个元素作为基准然后partition，返回基准位置    int partition(vector&lt;int&gt;&amp; nums, int left, int right) &#123;        int x = nums[left];        int i = left, j = right;        while(i&lt;j) &#123;            while(i&lt;j &amp;&amp; nums[j] &gt;= x) j--;            while(i&lt;j &amp;&amp; nums[i] &lt;= x) i++;            swap(nums[i],nums[j]);        &#125;        swap(nums[i],nums[left]);        return i;    &#125;    int randomPartition(vector&lt;int&gt;&amp; nums, int left, int right) &#123;        int i = rand() % (right - left + 1) + left;        swap(nums[i], nums[left]);        return partition(nums,left,right);    &#125;
partition用for循环的版本（容易导致分布不均）：private static &lt;T&gt; int partition(T[] arr, int low, int high, Comparator&lt;T&gt; comparator) &#123;    T pivot = arr[high];  // 1. 选最后一个元素为基准（固定）    int i = low - 1;      // 2. 小元素边界指针（初始在low前面）        for (int j = low; j &lt; high; j++) &#123;  // 3. j遍历所有元素（除了基准）        if (comparator.compare(arr[j], pivot) &lt;= 0) &#123;  // 4. 当前元素 ≤ 基准            i++;                       // 小元素区域扩大            swap(arr, i, j);           // 把当前小元素放到小区域        &#125;    &#125;        swap(arr, i + 1, high);  // 5. 基准归位到小元素区域后面    return i + 1;            // 返回基准位置&#125;另一个类似的题目

寻找两个正序数组的中位数public double findMedianSortedArrays(int[] nums1, int[] nums2) &#123;	int m = nums1.length, n = nums2.length;	int total = m + n;	if (total % 2 == 1) &#123;		// 奇数：找第 (total/2 + 1) 小的元素		return getKth(nums1, nums2, total / 2 + 1);	&#125; else &#123;		// 偶数：找第 (total/2) 小和第 (total/2 + 1) 小的平均数	return (getKth(nums1, nums2, total / 2) + getKth(nums1, nums2, total / 2 + 1)) / 2.0;	&#125;&#125;// 在两个有序数组中找第k小的数private int getKth(int[] nums1, int[] nums2, int k) &#123;		int m = nums1.length, n = nums2.length;	int start1 = 0, start2 = 0; // 两个数组的起始位置		while (true) &#123;			// 边界情况			if (start1 == m) return nums2[start2 + k - 1]; // nums1用完		if (start2 == n) return nums1[start1 + k - 1]; // nums2用完		if (k == 1)  return Math.min(nums1[start1], nums2[start2]); // 只剩1个要找的			// 正常情况		int half = k / 2;			int end1 = Math.min(start1 + half, m) - 1; // nums1的新位置				int end2 = Math.min(start2 + half, n) - 1; // nums2的新位置  			if (nums1[end1] &lt;= nums2[end2]) &#123;			// 抛弃nums1的前半部分			k -= (end1 - start1 + 1);			start1 = end1 + 1;		&#125; else &#123;		// 抛弃nums2的前半部分			k -= (end2 - start2 + 1);			start2 = end2 + 1;		&#125;	&#125;&#125;

