二叉树平衡二叉树AVL#include &lt;iostream&gt;#include &lt;algorithm&gt;using namespace std;struct Node &#123;    int key;    int height;    Node *left, *right, *parent;    Node(int key) : key(key), height(1), left(nullptr), right(nullptr), parent(nullptr) &#123;&#125;&#125;;int getHeight(Node *N) &#123;    if (N == nullptr)        return 0;    return N-&gt;height;&#125;int getBalance(Node *N) &#123;    if (N == nullptr)        return 0;    return getHeight(N-&gt;left) - getHeight(N-&gt;right);&#125;Node* rightRotate(Node *y) &#123;    Node *x = y-&gt;left;    Node *T2 = x-&gt;right;    x-&gt;right = y;    y-&gt;left = T2;    y-&gt;height = max(getHeight(y-&gt;left), getHeight(y-&gt;right)) + 1;    x-&gt;height = max(getHeight(x-&gt;left), getHeight(x-&gt;right)) + 1;    return x;&#125;Node* leftRotate(Node *x) &#123;    Node *y = x-&gt;right;    Node *T2 = y-&gt;left;    y-&gt;left = x;    x-&gt;right = T2;    x-&gt;height = max(getHeight(x-&gt;left), getHeight(x-&gt;right)) + 1;    y-&gt;height = max(getHeight(y-&gt;left), getHeight(y-&gt;right)) + 1;    return y;&#125;Node* insert(Node *node, int key) &#123;    if (node == nullptr)        return new Node(key);    if (key &lt; node-&gt;key)        node-&gt;left = insert(node-&gt;left, key);    else if (key &gt; node-&gt;key)        node-&gt;right = insert(node-&gt;right, key);    else        return node;    node-&gt;height = 1 + max(getHeight(node-&gt;left), getHeight(node-&gt;right));    int balance = getBalance(node);    if (balance &gt; 1 &amp;&amp; key &lt; node-&gt;left-&gt;key)        return rightRotate(node);    if (balance &lt; -1 &amp;&amp; key &gt; node-&gt;right-&gt;key)        return leftRotate(node);    if (balance &gt; 1 &amp;&amp; key &gt; node-&gt;left-&gt;key) &#123;        node-&gt;left = leftRotate(node-&gt;left);        return rightRotate(node);    &#125;    if (balance &lt; -1 &amp;&amp; key &lt; node-&gt;right-&gt;key) &#123;        node-&gt;right = rightRotate(node-&gt;right);        return leftRotate(node);    &#125;    return node;&#125;void preOrder(Node *root) &#123;    if (root != nullptr) &#123;        cout &lt;&lt; root-&gt;key &lt;&lt; &quot; &quot;;        preOrder(root-&gt;left);        preOrder(root-&gt;right);    &#125;&#125;int main() &#123;    Node *root = nullptr;    root = insert(root, 10);    insert(root, 20);    insert(root, 30);    insert(root, 40);    insert(root, 50);    insert(root, 25);    cout &lt;&lt; &quot;Preorder traversal of the constructed AVL tree is:\n&quot;;    preOrder(root);    return 0;&#125;

非递归实现先序遍历public List&lt;Integer&gt; preorderTraversal(TreeNode root) &#123;    List&lt;Integer&gt; result = new ArrayList&lt;&gt;();    if (root == null) return result;        Stack&lt;TreeNode&gt; stack = new Stack&lt;&gt;();    TreeNode cur = root;        while (cur != null || !stack.isEmpty()) &#123;        if (cur != null) &#123;            result.add(cur.val);     // 访问当前节点            stack.push(cur);         // 压栈            cur = cur.left;         // 遍历左子树        &#125; else &#123;            cur = stack.pop().right; // 回溯并转向右子树        &#125;    &#125;        return result;&#125;

中序遍历public List&lt;Integer&gt; inorderTraversal(TreeNode root) &#123;    List&lt;Integer&gt; result = new ArrayList&lt;&gt;();    Stack&lt;TreeNode&gt; stack = new Stack&lt;&gt;();    TreeNode cur = root;        while (cur != null || !stack.isEmpty()) &#123;        // 一直往左走，把所有左节点压栈 想想函数的递归调用        if (cur != null) &#123;            stack.push(cur);            cur = cur.left;        &#125; else &#123;	        // 弹出最左节点并访问	        cur = stack.pop();	        result.add(cur.val);	        	        // 转向右子树	        cur = cur.right;        &#125;    &#125;        return result;&#125;

后序遍历// 后序遍历示例（最难的），先序中序同理改顺序public List&lt;Integer&gt; postorder(TreeNode root) &#123;    List&lt;Integer&gt; res = new ArrayList&lt;&gt;();    Stack&lt;TreeNode&gt; stack = new Stack&lt;&gt;();    if (root != null) stack.push(root);        while (!stack.isEmpty()) &#123;        TreeNode cur = stack.pop();                if (cur != null) &#123;            // 标记：再次遇到时输出            stack.push(cur);           // 把自己压回去（下次输出）            stack.push(null);          // 放 null 作为标记                        // 按倒序压入子树            if (cur.right != null) stack.push(cur.right);            if (cur.left != null) stack.push(cur.left);        &#125; else &#123;            // 遇到 null，说明下一个该输出了            res.add(stack.pop().val);        &#125;    &#125;    return res;&#125;

