class UnionFind&#123;    // 本题因为是按行列进行查找，优化可以直接采用哈希表public:    // 哈希表映射关系[key,parent]    unordered_map&lt;int,int&gt; parent;    // 总共有多少不连通的并查集    int count = 0;    // 并查集查找首领节点操作    int Find(int index)&#123;        if(!parent.count(index))&#123;            parent[index] = index;            count++;        &#125;        // 查找并查集的首领节点并优化        if(parent[index] != index)            parent[index] = Find(parent[index]);        return parent[index];    &#125;    // 并查集合并操作    void Uniod(int index1,int index2)&#123;        int parent1 = Find(index1);        int parent2 = Find(index2);        if(parent1 != parent2)&#123;            parent[parent1] = parent2;            count--;        &#125;    &#125;&#125;;class UnionFind &#123;private:    vector&lt;int&gt; parent;    int count;public:    UnionFind(int count) : count(count) &#123;        parent.resize(count);        for(int i=0;i&lt;count;i++) &#123;            parent[i] = i;        &#125;    &#125;;    void Union(int a, int b) &#123;        int pa = Find(a);        int pb = Find(b);        if(pa != pb) &#123;            parent[pa] = pb;            count--;        &#125;    &#125;    int Find(int x) &#123;        if(x!=parent[x]) &#123;            parent[x] = Find(parent[x]);        &#125;        return parent[x];    &#125;    int GetCount() &#123;        return count;    &#125;&#125;;
