自定义数据结构类考点手写堆// 堆化函数，调整堆的结构void heapify(vector&lt;int&gt;&amp; arr, int n, int i) &#123;    int largest = i;     // 初始化最大元素为根节点    int left = 2 * i + 1;  // 左子节点    int right = 2 * i + 2; // 右子节点    // 如果左子节点大于根节点    if (left &lt; n &amp;&amp; arr[left] &gt; arr[largest])        largest = left;    // 如果右子节点大于当前最大节点    if (right &lt; n &amp;&amp; arr[right] &gt; arr[largest])        largest = right;    // 如果最大元素不是根节点，交换并递归堆化    if (largest != i) &#123;        swap(arr[i], arr[largest]);        heapify(arr, n, largest);    &#125;&#125;// 堆排序函数void heapSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    // 构建最大堆    for (int i = n / 2 - 1; i &gt;= 0; i--)        heapify(arr, n, i);    // 一个个从堆中取出元素    for (int i = n - 1; i &gt; 0; i--) &#123;        swap(arr[0], arr[i]);  // 将当前最大元素移动到数组末尾        heapify(arr, i, 0);    // 重新调整堆    &#125;&#125;

