class State &#123;public:    int id;    double curMaxP;    State(int id, double curMaxP) : id(id), curMaxP(curMaxP) &#123;&#125;    bool operator&lt;(const State&amp; other) const &#123;        // 在这里定义比较规则，例如根据状态的某些属性进行比较        // 这里假设状态有一个整数属性 value，根据 value 的大小来比较        return curMaxP &lt; other.curMaxP;    &#125;&#125;;class Solution &#123;public:    double maxProbability(int n, vector&lt;vector&lt;int&gt;&gt;&amp; edges, vector&lt;double&gt;&amp; succProb, int start_node, int end_node) &#123;        // 创建图        vector&lt;vector&lt;pair&lt;int,double&gt;&gt;&gt; graph(n);        for(int i=0;i&lt;edges.size();i++) &#123;            auto edge = edges[i];            int from = edge[0];            int to = edge[1];            double weight = succProb[i];            graph[from].push_back(&#123;to,weight&#125;);            graph[to].push_back(&#123;from,weight&#125;);        &#125;                // 需要按照state排序，每次找最大的        //! 这里的state类可以换成pair&lt;double,int&gt;，这样会默认按照double排序        priority_queue&lt;State&gt; pq;        vector&lt;double&gt; maxDist(n,-1);        State start(start_node, 1);        pq.push(start);        while(!pq.empty()) &#123;            auto [curId, curMaxP] = pq.top();            pq.pop();                        // 找到当前最大的            if(curId == end_node) return curMaxP;            // 如果比当前记录的还小那就算了            if(curMaxP &lt; maxDist[curId]) continue;            // 遍历他相邻节点            for(auto [nexId, weight]:graph[curId]) &#123;                double newDist = curMaxP*weight;                if(maxDist[nexId] &lt; newDist) &#123;                    // 更大                    maxDist[nexId] = newDist;                    pq.push(&#123;nexId, newDist&#125;);                &#125;            &#125;        &#125;        return 0;    &#125;&#125;;

